M = (B + C)/2;

draw(A--B--C--cycle);
draw(A--M);

label("$A$", A, SW);
label("$B$", B, NE);
label("$C$", C, SE);
label("$M$", M, E);
label("$2$", (A + B)/2, NW, red);
